const drops = $input.all();

// Group by province for better messaging
const byProvince = {};
drops.forEach(item => {
  const province = item.json.province || 'Unknown';
  if (!byProvince[province]) byProvince[province] = [];
  byProvince[province].push(item.json);
});

// Build Slack message blocks
const blocks = [
  {
    type: 'header',
    text: { type: 'plain_text', text: 'Price Drop Alert - ' + new Date().toLocaleDateString('en-ZA') }
  },
  {
    type: 'section',
    text: { type: 'mrkdwn', text: `*${drops.length} price drops detected today*` }
  }
];

// Add top 5 drops
const top5 = drops.slice(0, 5).map(d => d.json);
top5.forEach(drop => {
  blocks.push({
    type: 'section',
    text: {
      type: 'mrkdwn',
      text: `*${drop.title}*\n` +
            `~~R${Number(drop.previous_price).toLocaleString()}~~ → *R${Number(drop.current_price).toLocaleString()}* (-${drop.drop_percentage}%)\n` +
            `Saving: R${Number(drop.drop_amount).toLocaleString()} | ${drop.city}, ${drop.province}\n` +
            `${drop.bedrooms} bed | ${drop.bathrooms} bath | ${drop.property_type}\n` +
            `<${drop.url}|View Listing>`
    }
  });
  blocks.push({ type: 'divider' });
});

// Summary text
const totalSavings = drops.reduce((sum, d) => sum + Number(d.json.drop_amount), 0);
const avgDrop = drops.reduce((sum, d) => sum + Number(d.json.drop_percentage), 0) / drops.length;

return [{
  json: {
    drops_count: drops.length,
    total_savings: totalSavings,
    avg_drop_pct: avgDrop.toFixed(1),
    by_province: byProvince,
    slack_blocks: JSON.stringify(blocks),
    top_drop: drops[0]?.json || {},
    all_drops: drops.map(d => d.json)
  }
}];

const subscriber = $('Get Alert Subscribers').item.json;
const allDrops = $('Build Alert Messages').item.json.all_drops;

// Filter drops matching subscriber's saved search criteria
const matchingDrops = allDrops.filter(drop => {
  if (subscriber.max_price && drop.current_price > subscriber.max_price) return false;
  if (subscriber.min_bedrooms && drop.bedrooms < subscriber.min_bedrooms) return false;
  if (subscriber.province_filter && subscriber.province_filter !== 'all' && drop.province !== subscriber.province_filter) return false;
  if (subscriber.property_type_filter && subscriber.property_type_filter !== 'all' && drop.property_type !== subscriber.property_type_filter) return false;
  return true;
});

if (matchingDrops.length === 0) return [];

const emailHtml = `
<!DOCTYPE html>
<html>
<head><style>
body { font-family: Arial, sans-serif; color: #333; }
.header { background: #1a472a; color: white; padding: 20px; text-align: center; }
.property { border: 1px solid #ddd; margin: 15px 0; padding: 15px; border-radius: 8px; }
.price-drop { color: #e53e3e; font-size: 18px; font-weight: bold; }
.old-price { text-decoration: line-through; color: #999; }
.new-price { color: #2d6a4f; font-size: 22px; font-weight: bold; }
.badge { background: #e53e3e; color: white; padding: 3px 8px; border-radius: 12px; font-size: 12px; }
.cta { background: #1a472a; color: white; padding: 10px 20px; text-decoration: none; border-radius: 5px; display: inline-block; margin-top: 10px; }
</style></head>
<body>
<div class="header">
  <h1>Price Drop Alert</h1>
  <p>${matchingDrops.length} price drop(s) matching your saved search</p>
</div>
<div style="padding: 20px;">
${matchingDrops.slice(0, 5).map(drop => `
  <div class="property">
    <h3>${drop.title}</h3>
    <p>
      <span class="old-price">R${Number(drop.previous_price).toLocaleString()}</span>
      &nbsp;→&nbsp;
      <span class="new-price">R${Number(drop.current_price).toLocaleString()}</span>
      &nbsp;<span class="badge">-${drop.drop_percentage}%</span>
    </p>
    <p>You save: <strong>R${Number(drop.drop_amount).toLocaleString()}</strong></p>
    <p>${drop.bedrooms} bed | ${drop.bathrooms} bath | ${drop.property_type}<br>${drop.city}, ${drop.province}</p>
    <a href="${drop.url}" class="cta">View Property</a>
  </div>
`).join('')}
</div>
<p style="text-align:center;color:#999;font-size:12px;">PuraEstate - Unsubscribe</p>
</body></html>`;

return [{
  json: {
    to: subscriber.user_email,
    name: subscriber.user_name,
    phone: subscriber.user_phone,
    notify_whatsapp: subscriber.notify_whatsapp,
    notify_email: subscriber.notify_email,
    matching_drops: matchingDrops.length,
    email_html: emailHtml,
    whatsapp_message: `PuraEstate Price Alert: ${matchingDrops.length} properties matching your search have dropped in price! Top drop: ${matchingDrops[0].title} now R${Number(matchingDrops[0].current_price).toLocaleString()} (-${matchingDrops[0].drop_percentage}%). View: ${matchingDrops[0].url}`
  }
}];
